const Q_ECONOMICS_1997=[{"id": "objective>Economics>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">With a given level of money income, a consumer maximizes satisfaction from the consumption of goods and services when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total utility derived from each good or service is increasing at an increasing rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility derived from each good or service is increasing at the same rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility derived per naira spent is the same for all the goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility derived from all the goods and services is large.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer is in equilibrium when he maximizes his utility given his income and the market prices. For this, he will compare the marginal utilities of the different commodities he wants to buy and also the marginal utility of each commodity to its price. <br/> If he finds that the marginal utility of good A is higher than that of good B, he will substitute A for B till their marginal utilities are equalized ( the same) and if the last naira spent on good A gives him less marginal utility, he will withdraw this amount from A spend it on good B.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ike's scale of preference reveals that he prefers bananas to pawpaw, pawpaw to oranges and oranges to banana, Ike's preferences are therefore</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inconsistent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consistent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transitive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rational</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A phenomenon that occurs when individual's choice ( as a direct indicator of individual's preferences) between two alternatives is inconsistent with the way an individual ranks \" selling\" price of these alternatives ( where price serves as an indirect indicator of his preferences) becomes known as a preference reversals.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the features of a free market economy is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resources are directed by the price mechanism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers do not earn equal wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the profit motive is severely constrained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decisions on the economy are taken by bureaucratic structures</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free market economy system is also known as capitalist economy. In this market, the forces of demand and supply ( price system/mechanism) determines the price in the market.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the fundamental differences between a capitalist and a socialist economy is that while</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the former is characterized by complete government ownership of resources, the latter is characterized by complete private ownership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the former, prices act as signals in the allocation of resources, it is the central authority that performs this function in the latter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxes are levied in a capitalist economy, there is no taxation in a socialist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income and wealth are equally distributed in the socialist economy, this is not so in a capitalist economy.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between a capitalist economy and socialist economy is that: <br/> - capitalist economy resources is controlled by private individual while socialist economy resources are control by the government or state <br/> - in capitalist economy system, the price mechanism/system determines the price while the government or state determines the price in a socialist economy system</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that at the beginning of 1973, Nigeria with a birth rate of 3% per annum had a population of 75million. This implied that in that year</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the population increased by 2.25million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there were 2.25 million live births</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the governement have to make provisions for 2.25million children </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.25 million children were born</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The birth rate is the number of live births per 1000 of population per year. Therefore, a birth rate of 3% per annum means that there were 30 live births per 1000 of population in that year. If the population was 75 million, then the number of live births would be 0.03 x 75 million = 2.25 million. Therefore, the population increased by 2.25 million in that year.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a country's population is experiencing increasing returns, that country is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overpopulated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economically poor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over producing goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">underpopulated</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a country's population is experiencing increasing returns, it means that the country is overproducing goods and services. Increasing returns indicate that the country's production processes are becoming more efficient and productive, leading to a higher output of goods and services. <br/>  <br/> This increased production can result from factors such as economies of scale, technological advancements, improved infrastructure, or better utilization of resources. As a result, the country is able to produce more output with the same or fewer resources.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a country if the population of people who are below 15years is 45% and those above 60 years is 30%, this implies that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dependency ratio is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population is optimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active population is large</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population is growing according to Malthus theory</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dependency ratio is an age-population ratio of those typically not in the labour force i.e those within the age of 0 - 17 and 60 years and above. The higher the dependency ratio , the higher the lower the productivity growth.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the objectives of of Nigeria's current population policy is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce the birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the emigration rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhance longetivity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The policy has an overall goal of improving the life and standard of living for all Nigerians through population control. It also stresses the need for urgent measures to address Nigeria's high fertility rate, through expanding access to modern contraceptive methods across the country.</div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Labour productivity is the ratio of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour to output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man hours to output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output to man-hours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average product to man-hours</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The labour productivity ratio is a metric expressing the number of work units produced per time worked. Productivity ratios essentially quantify output/input, with input being time worked and output being work units.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of cost which has to be covered for a firm to continue production in the short-run is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overhead cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average variable cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Average variable cost (AVC) represents the variable costs per unit of output. In the short run, a firm can reduce its fixed costs because they are generally fixed and cannot be changed quickly. However, the firm must cover its variable costs (represented by the average variable cost) to continue production in the short run. As long as the price of the product covers or exceeds the average variable cost, the firm can cover its variable expenses and continue operating, even if it doesn't cover its total costs (fixed and variable).</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Point P suggests that the economy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reaching full employment but not full production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attaining full production but not full employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">under capitalized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attaining both full employment and full production</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Any point on the curve indicate that the resources are full employed or technologically efficient or production is fully employed.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The movement of curve I to II suggests</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an improvement in capital goods technology but not in consumer goods technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a movement from unemployment to full employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that the output for the society has declined</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a gain in consumer goods technique and not in capital goods technique</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram above, there is a shift in the curve of capital goods while consumer goods remains constant i.e capital goods shift from i to ii.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the curve which represents the firm's short-run average variable cost is curve</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Curve II represent the average variable cost, curve I represent the average fixed cost, curve III represent average cost or average total cost and curve IV represent the marginal cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A good is said to be inferior if its demand </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rises as income rises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">falls as income rises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rises as its price falls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is perfectly inelastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inferior goods are goods in which as income increases, demand falls. It has a positive income elasticity of demand.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given a market demand curve Q = 120 - 2p and a supply curve Q = 4p, the equilibrium price and quantity respectively are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 and 80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 and 120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 and 60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60 and 240</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qd = 120 - 2p  <br/> Qs = 4p <br/>  <br/> Equilibrium price : Qd = Qs <br/> 120 - 2p = 4p <br/> 120 = 4p +2p <br/> 120 = 6p <br/> divide both side by P <br/> P = #20 <br/>  <br/> To find equilibrium quantity, sub p into any equation <br/> Qd = 120 -2p <br/>  = 120 - 2( 20) <br/> = 120 - 40 <br/> = 80kg/units <br/> or <br/> Qs = 4p <br/> = 4(20) <br/> = 80kg/units</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a demand curve that intersects a perfectly inelastic supply curve shifts rightward, then </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the equilibrium price and quantity will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">only the price will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">only the quantity will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the price will remain constant </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the case of a perfectly inelastic supply curve, the quantity supplied does not change regardless of the price. Therefore, if the demand curve shifts rightward (indicating an increase in demand), both the equilibrium price and quantity will increase. The price increases because the increased demand creates a higher willingness to pay, and the quantity increases because the demand has increased.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The elasticity of demand for a firm's product is 2, if the firm reduces its price by 20 percent, its sales revenue will increase by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10 percent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20percent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 percent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 percent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The elasticity of demand is a measure of how much the quantity demanded of a good responds to a change in the price of that good. In this case, the elasticity of demand is 2, which means that a 1 percent decrease in price leads to a 2 percent increase in quantity demanded. Therefore, a 20 percent decrease in price would lead to a 40 percent increase in quantity demanded, assuming all else remains constant. This would result in an increase in total revenue by 40 percent.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the percentage change in the income of the consumers of an industrial product is less than the resulting percentage change in the quantity demanded of the product, then the income elasticity of demand for the product is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than one </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to zero</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The income elasticity of demand measures how much the quantity demanded of a good responds to a change in consumers' income. If the percentage change in quantity demanded is less than the percentage change in income, the income elasticity of demand is less than one. This is because the quantity demanded is not very responsive to changes in income, indicating that the good is a necessity.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A market where there are many differentiated products is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopolistic competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligopoly</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monopolistic competition is a market situation where there are many firms selling a differentiate product. It has both characteristics of monopoly and perfect competition.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> from the diagram above, the quantity of output is determined by the point </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above represent the short run of a perfect competition. The highest output of the firm is at point F where the firm cannot exceed.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best channel of distribution of baked bread is through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wholesalers to retailers then to consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct sales to consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholesalers to consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retailers to consumers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Retails stores and supermarkets is one of the most common channels, where bread is distributed to grocery stores and supermarkets, making it easily accessible to large number of customers.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of business organization which is characterized by limited authority and liability of the individual owners is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint stock company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperative society</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liability of shareholders is limited to the amount contributed to the company. The private properties of the shareholders will not be touched in the event of liquidation.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shares that must be redeemed first at liquidation of a company are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">preference shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-voting ordinary shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debentures</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A preference share is the type of share which has priority in terms of dividend paymenr and repayment of capital in the event of winding up.They have a fixed rate of dividends and holders receive dividends before others.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The suggestion that peasants in africa have backward-bending supply curves of output implies that their response to an increase in the price of their crops will be to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase their output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease their output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">keep their output constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hoard their output</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The suggestion that peasants in Africa have backward-bending supply curves of output implies that their response to an increase in the price of their crops will be to decrease their output. This is because a backward-bending supply curve indicates that as prices increase beyond a certain point, the quantity supplied decreases. This could be due to a variety of reasons, such as the desire to maintain a certain standard of living rather than maximize income, or the diminishing marginal utility of income.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important requirement for increasing agricultural output in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">for the government to go into large scale farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">to employ relevant foreign technology and reform the land tenure system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to increase farmers' incomes and improve the farming techniques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to employ more extension workers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increasing agricultural output requires a combination of factors. While technology and land reform are important, they are not the most crucial. The most important requirement is to increase farmers' incomes and improve farming techniques. This is because when farmers have more income, they can invest in better farming equipment, seeds, and other inputs that can increase their output. Improved farming techniques can also lead to higher yields. Therefore, the correct answer is 'to increase farmers' incomes and improve the farming techniques'.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the effect of inelastic demand for agricultural products on the income of a farmer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a price rise results in its fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a price fall results in its fall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a price fall results in its rise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a price rise leaves the income unchanged</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic demand refers to a situation where the quantity demanded does not change significantly when the price changes. Therefore, if the demand for agricultural products is inelastic, a fall in price will result in a fall in the farmer's income because the quantity demanded will not increase significantly to offset the decrease in price. Therefore, the correct answer is 'a price fall results in its fall'.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plywood industries are often located near the sourse of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">finance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A plywood firm would be located near the source of its raw materials to ensure easy access to the materials, before selling to its target.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm is said to have benefited from external economies in production if it has realized</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a more efficient management of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a better combination of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced resource costs due to operations of other firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a higher profit level due to increased sales.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External economies arises from localization of industry. The benefits a firm derives from the concentration or localization of industries in a particular area.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the dangers of the localization of industries is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">residual unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclical unemployment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Disadvantages of localisation of industries are:  <br/> - it causes structural unemployment <br/> - increase in crime rate <br/> - it leads to congestion <br/> - it causes environmental pollution <br/> - it encourages rural-urban migration</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glut in the world market for crude oil means a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a fall in crude oil production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an excess supply of crude petroleum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a higher crude oil price offered by the buyer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a higher crude oil price demanded by the seller</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum glut means the production of petroleum is greater than the demand. When petroleum price drops due to over population, the market cites as an oil glut.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main problem of the organizaton of petroleum exporting countries is how to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent members from violating their quota</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhance the quality of petroleum products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compete with the North sea producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure viable crude reserves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problem is that there is constant disagreement among members of OPEC in fixing of prices and production quotas, and failure to implement agreed prices and production quotas.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : OPEC"}, {"id": "objective>Economics>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important attribute of money is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">homogeneity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divisibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general acceptability</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important attribute of money is its general acceptability. Money serves as a medium of exchange, and for it to effectively perform this function, it must be generally accepted by all individuals, businesses, and other entities within an economy. If money is not generally accepted, it loses its value as a medium of exchange. Therefore, the option 'general acceptability' is the correct answer.</div>", "topic": "MONEY : CHARACTERISTICS OF MONEY"}, {"id": "objective>Economics>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is inflationary?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in taxation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in savings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in money supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in government expenditure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increase in government expenditure or demand will lead to inflation. When the demand or expenditure for goods and services is greater than supply, this results in inflation ( demand pull inflation).</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In commercial banking and account from which the customer cannot withdraw money instantly is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand deposit account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time deposit account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">special deposit account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">savings deposit account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Time deposit is also known as fixed deposit account is the type of account that is usually operated by individuals and organisations who have excess liquidity. Notice of seven days must be given before withdrawal and it attracts higher interest rate.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Banks can create more money by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing its cash ratio with the central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issuing more bank cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accepting more deposits from customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lending out money from customers' deposits</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial banks can create money or credit in the following ways, they are: <br/> - by granting loans to members of the public and charging interest on them <br/> - by granting overdraft to customers having current account <br/> - commercial banks are required by law to keep certain percentage of their deposit with the central bank known as cash ratio or liquidity ratio or cash reserve <br/> - commercial banks can create credit or money by purchasing treasury bills from the government and by discounting bills of exchange</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stocks and shares as well as bonds are examples of instruments used in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commodity markets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">money markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">security markets</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital market is a market for medium-term and long term loans. The instruments used in capital market are: stocks, shares, bonds etc.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of legally permissible means to reduce tax liabilities is known as tax </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evasion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avoidance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exemption</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tax avoidance is the legal usage of a tax regime in a single territory to one's own advantage to reduce the amount of tax that is payable by means that are within the law.</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest proportion of government revenue in Nigeria comes from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">export of raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">income taxes on individuals and businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customs duties and excise taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loans and grants from industrially advanced countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main source of government revenue are: petroleum profit tax, companies income tax, personal income tax, custom duties /tarrifs ( import duties, export duties).</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors which is likely to check the growth of public debts is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bridging the resource gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt repudiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt rescheduling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt-equity swap</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bridging the resource gap is a factor that can check the growth of public debts. This is because when the resource gap (the difference between the resources a country needs to meet its development goals and the resources it can mobilize domestically) is bridged, it reduces the need for borrowing, hence, checking the growth of public debts.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the marginal propensity to consume is 0.75 and private investment increases by #10 billion while government expenditure decreases by 15 billion, GDP will decrease by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#12 billion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#15 billion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#20 billion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#25 billion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in GDP can be calculated using the multiplier effect formula which is 1/(1-MPC).  <br/>  <br/> Here, the Marginal Propensity to Consume (MPC) is 0.75.  <br/>  <br/> So, the multiplier is 1/(1-0.75)  <br/> = 4.  <br/> The net change in spending is the increase in private investment minus the decrease in government expenditure, which is #10 billion - #15 billion = -#5 billion.  <br/>  <br/> Therefore, the change in GDP is the multiplier times the change in spending, which is: <br/>  4 x -#5 billion <br/>  = -#20 billion.  <br/>  <br/> Hence, GDP will decrease by #20 billion.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: investment     =  #100 million <br/>           consumption  =  #200m + 0.75Y <br/>                              Y  =  C + I <br/> where, Y = income, C = Consumption and I = Investment <br/> what is the income level to the nearest million?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#100 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#300 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1,000 million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1,200 million</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Y = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">a + I</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1 - b</span> <br/>  <br/> where a = autonomous consumption ( 200) <br/>  I = investment expenditure (100) <br/> b = Marginal propensity to consume ( 0.75) <br/>  <br/> Therefore, Y = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">200 + 100</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1 - 0.75</span> <br/>  <br/>  Y = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">300</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.25</span> <br/>  <br/> Y = #1,200  million</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total money values of all goods and services produced in a country during a certain period is measured by using the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output method </div>", "<div style=\"font-family:Cambria;font-size:17px;\">factor method</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Output method/Approach is also known as value-added method. In this method, national income is measured in terms of the monetary value of goods and services produced in the country.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization of government-owned companies means the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">relinquishing of government's equity participation to private individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recapitalization of distressed government-owned companies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint participation of government and private individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercialization and deregulation of the economy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatisation is a policy designed to enable individuals and private or corporate organisations take over the ownership and control of government businesses such as public companies and corporations.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of the total volume of output in an economy is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">level of wholesale prices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of the labour force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of total expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composition of consumer spending</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total volume of output in an economy is primarily determined by the level of total expenditure. This is because the total expenditure in an economy is the sum of all spending on goods and services produced in the economy. This includes consumer spending, investment spending, government spending, and net exports. Therefore, the more the total expenditure, the higher the volume of output in the economy.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factor in ensuring economic development is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">effective mobilization of domestic savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of foreign capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">formulation of appropriate government policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attraction of foreign ainds and grants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There should be good development plans and thier execution will promote economic development and also a stable government generally encourages economic development.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following classes of goods accounts for the largest proportion of Nigeria's imports?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food and animal products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemicals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">machinery and transport equipment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The class of goods that accounts for the largest proportion of Nigeria's imports is machinery and transport equipment. This is because Nigeria, like many developing countries, relies heavily on imported machinery and transport equipment for its industrial and transportation sectors. These imports are crucial for the country's economic development as they provide the necessary tools and equipment for production and transportation. The other options like food and animal products, consumer goods, and chemicals do not account for the largest proportion of Nigeria's imports.</div>", "topic": "INTERNATIONAL TRADE : INTRODUCTION"}, {"id": "objective>Economics>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Counter trading is an international arrangement whereby</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goods and services are exchanged in a manner similar to barter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods and services are sold on the counter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crude oil is sold to a foreign country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods are shipped to the countries on which the united nations has placed a trade embargo</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Counter trade refers to the trade involving the exchange of goods or services for other goods or services. It may or may not involve partial payment in cash for goods or services bought but will not make complete payment in cash</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In recent years. Nigeria's balance of payments has continued to register a deficit due to <br/> I. increased government overseas' spending <br/> II. increasing prices of exports <br/> III. rising import prices  <br/> IV. more payments to overseas' investors</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria BOP deficits emerged in 2008 as a result of the global financial crisis and plummeting oil prices on foreign markets. The deficit influenced fiscal balance in Nigeria because of the over reliance of the Nigerian economy on foreign exchange</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organization which provides credit to help countries achieve short-term balance in their balance of payments is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Economic Community of West African States</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International Monetary Fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International Bank for Reconstruction and Development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">African Development Bank</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International Monetary Fund was established to encourage balance of payment equilibrium and to stabilise exchange rate among member countries.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>1997>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important feature of a cartel is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">members do not reduce price below the cartel prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">each member has a fixed output above which it is not expected to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a powerful member fixes the price at which others will sell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members fix the prices for their products</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A cartel is a group of independent market participants who collude with each other in order to improve their profits and maintain control over the market. One of the key features of a cartel is that the members agree to fix the prices for their products. This is done to prevent competition among the members, which can lead to a decrease in prices and profits.</div>", "topic": "MARKET STRUCTURE : OLIGOPOLY"}];
